                    style={{ width: `${scrollProgress}%` }}
                >
                    <div className="absolute right-0 top-1/2 -translate-x-1/2 w-3 h-3 bg-white rounded-full shadow-[0_0_10px_rgba(255,255,255,0.8)] scale-75 border-2 border-indigo-500"></div>
                </div>
            </div>
        </header>


        {/* --- Main Workspace Grid --- */}
        <div className="flex-1 flex overflow-hidden">

            {/* 1. Left Panel: Chat (Fixed Width) */}
            <div className="w-[400px] flex flex-col border-r border-slate-800 bg-slate-950/50 backdrop-blur-sm relative z-10">
                {/* Chat Header */}
