                                    <Brain size={16} />
                                </button>
                                <button 
                                    type="button" 
                                    onClick={toggleRecording} 
                                    className={`p-2 rounded-lg transition-all duration-300 ${
                                        isRecording 
                                        ? 'bg-red-500/10 text-red-500 animate-pulse border border-red-500/30' 
                                        : isTranscribing
